import Highcharts from 'highcharts';
import HighchartsReact from 'highcharts-react-official';
import React, { Component } from 'react';

const casesNouns = {
    'confirmed': 'Confirmed Cases',
    'recovered': 'Recovered Patients',
    'deaths': 'Deaths',
};

export default class Comparison extends Component {

    constructor(props) {
        super(props);

        const { match: { params: { status } } } = this.props;

        const casesNoun = casesNouns[status.toLowerCase()];

        this.state = {

            title: {
                text: `COVID-19 ${casesNoun}`,
            },

            subtitle: {
                text: 'Source: covid19api.com'
            },

            yAxis: {
                title: {
                    text: `${casesNoun}`
                }
            },

            xAxis: {
                type: 'datetime',
            },

            legend: {
                layout: 'vertical',
                align: 'right',
                verticalAlign: 'middle'
            },

            plotOptions: {
                series: {
                    label: {
                        connectorAllowed: false
                    },
                }
            },

            responsive: {
                rules: [{
                    condition: {
                        maxWidth: 500
                    },
                    chartOptions: {
                        legend: {
                            layout: 'horizontal',
                            align: 'center',
                            verticalAlign: 'bottom'
                        }
                    }
                }]
            },

            series: [],

        };
    }

    render() {
        return <HighchartsReact highcharts={Highcharts} options={this.state} />;
    }

    async componentDidMount() {
        const { match: { params: { countries: countryNames, status } } } = this.props;
        try {
            const countries = await Promise.all(
                countryNames
                    .split(';')
                    .map(countryName => fetch(`https://api.covid19api.com/total/country/${countryName.toLowerCase()}/status/${status.toLowerCase()}`)
                        .then(response => response.json())));
            this.setState({
                series: countries.map(countryData => ({
                    name: countryData[0]['Country'],
                    data: countryData.map(({ Date: date, Cases: cases }) => ({
                        x: Date.parse(date),
                        y: cases
                    })),
                })),
            });
        } catch (error) {
            console.error(error);
        }
    }

}