import Highcharts from 'highcharts';
import HighchartsReact from 'highcharts-react-official';
import React, { Component } from 'react';

export default class Summary extends Component {

    constructor(props) {
        super(props);

        const { criterion } = this.props;

        this.state = {
                chart: {
                    plotBackgroundColor: null,
                    plotBorderWidth: 0,
                    plotShadow: false
                },
                title: {
                text: `COVID-19<br>${criterion}`,
                    align: 'center',
                    verticalAlign: 'middle',
                    y: 60
                },
                tooltip: {
                    pointFormat: '{series.name}: <b>{point.percentage:.1f}%</b>'
                },
                accessibility: {
                    point: {
                        valueSuffix: '%'
                    }
                },
                plotOptions: {
                    pie: {
                        dataLabels: {
                            enabled: true,
                            distance: -50,
                            style: {
                                fontWeight: 'bold',
                                color: 'white'
                            }
                        },
                        startAngle: -90,
                        endAngle: 90,
                        center: ['50%', '75%'],
                        size: '110%'
                    }
                },
                series: [{
                    type: 'pie',
                name: '% of Cases',
                    innerSize: '50%',
                    data: [
                        {
                            name: 'Other',
                        y: 100,
                            dataLabels: {
                                enabled: false
                            }
                        }
                    ]
                }]
        };
    }

    render() {
        return <HighchartsReact highcharts={Highcharts} options={this.state} />;
    }

    async componentDidMount() {
        const { criterion } = this.props;
        const { Countries: countries } = await (await fetch(`https://api.covid19api.com/summary`)).json();
        countries.sort(({ [criterion]: a }, { [criterion]: b }) => b - a);
        this.setState({
            series: [{
                data: [
                    ...countries.slice(0, 10).map(({ Country: name, [criterion]: cases }) => ([name, cases])),
                    ['Rest of the World', countries.slice(10).map(({[criterion]: cases}) => cases).reduce((a, b) => a + b, 0)],
                ],
            }],
        });
    }

}